CREATE TABLE "video2"."process_html" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "started_at" timestamptz NOT NULL, "completed_at" timestamptz, "failed_at" timestamptz, "render_id" uuid NOT NULL, "attempt_count" integer NOT NULL DEFAULT 0, "org_id" uuid NOT NULL, "api_key_id" uuid, PRIMARY KEY ("id") , FOREIGN KEY ("render_id") REFERENCES "video2"."renders"("id") ON UPDATE restrict ON DELETE no action, FOREIGN KEY ("org_id") REFERENCES "identity"."orgs"("id") ON UPDATE restrict ON DELETE no action, FOREIGN KEY ("api_key_id") REFERENCES "identity"."api_keys"("id") ON UPDATE restrict ON DELETE no action);
CREATE EXTENSION IF NOT EXISTS pgcrypto;
